Future<void> showSelection() async {
  final selected = await Get.bottomSheet(
    Container(
      height: 250,
      child: Column(
        children: [
          ListTile(
            title: Text('Option 1'),
            onTap: () => Get.back(result: 'Option 1'),
          ),
          ListTile(
            title: Text('Option 2'),
            onTap: () => Get.back(result: 'Option 2'),
          ),
        ],
      ),
    ),
  );

  if (selected != null) {
    Get.snackbar('Selected', selected);
  }
}

